VALUES
  ('elementary-e0adf6cd-moex-00109', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '丙老師認為學習動機不是來自於外在的賞罰，而是來自於思考活動，如信念、期待、目標、價值等的重視， 因此在教學過程中非常重視如何激勵學生內在的成就動機。此種理念比較接近下列何種理論？', '["認知學說動機論", "行為主義動機論", "人本主義動機論", "經驗主義動機論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00110', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '甲校長認為雖然每一所學校的教育目的與組織結構都相似，甚至課程與教學也相似，但因為各自的歷史背 景、社區環境、組合成員都不同，意即每所學校都有它獨特的脈絡與情境，所以各所學校都是一個非常獨 特的文化體系，應發展自己的學校特色。有關他的理念比較接近下列何種理論？', '["象徵互動論（symbolicinteractionism）", "結構功能理論（structuralfunctionalism）", "衝突理論（conflicttheory）", "現代主義（modernism）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00111', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '學者叔曼（L.S.Shulman）研究指出，認知、後設認知、情緒、目的、隱含的心理及情感狀態，屬於教室 中教與學的何項潛在決定因素？', '["能力", "行動", "思想", "情境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00112', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '優等「教育計畫」的核心內容有四，四者要成系統結構，計畫的四大核心內容是計畫目標、經營策略、配 套措施及下列何者？', '["執行項目", "理論基礎", "研究分析", "發展方向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00113', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '我國為保障學生學習權及家長教育選擇權，提供學校以外之其他教育方式及內容，頒行有高級中等以下教 育階段非學校型態實驗教育實施條例。依據現行該條例的規範，下列敘述何者錯誤？', '["具有幼兒園、國中小學或高級中等學校入學資格者，得參與各該教育階段實驗教育", "參與國民教育階段實驗教育之學生，視同接受同一教育階段之學校教育", "實驗教育方式包含「個人實驗教育」", "實驗教育方式採取「團體實驗教育」者，學生總人數以30人為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00114', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '美國大部分的地方學區教育委員會（schoolboard）委員是如何產生的？', '["縣市長聘請", "人民投票選出", "州教育廳長指派", "地方學區教育局長聘請"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00115', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '因應時代的變遷逐漸發展出新的教育行政理論，下列何時期的理論著重於探討組織結構而較忽視組織成 員的行為？', '["傳統理論時期", "行為科學時期", "系統理論時期", "後現代時期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00116', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '謝恩（E.H.Schein）認為在文化的層次中，關於學生人性的本質是屬於那一層次的類別？', '["規範（norms）", "價值（values）", "外顯的成品（artifacts）", "基本假定（basicassumptions）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00117', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '我國國民中小學會因應地區、背景、情況與任務不同的屬性而改變運作的型態，例如有些學校設「輔導 室」，有些學校設「輔導處」；有些學校特教組隸屬於輔導室，有些學校隸屬於教務處，這種現象主要是 實施最符合下列何種方案的結果？', '["十二年國教", "教訓輔三合一", "學校組織再造", "九年一貫課程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00118', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何國的教育未受到英國殖民的影響？', '["菲律賓", "紐西蘭", "新加坡", "澳洲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
